app = Flask(__name__)


# =============================================================================
# Bedrock LLM Configuration
# =============================================================================

def create_bedrock_llm(tenant_id: str) -> ChatBedrock:
    """Create Bedrock LLM instance with tenant context.

    Args:
        tenant_id: Tenant identifier for request tagging

    Returns:
        Configured ChatBedrock instance
    """
    bedrock_client = boto3.client(
        "bedrock-runtime",
        region_name=AWS_REGION
    )

    return ChatBedrock(
        client=bedrock_client,
        model_id=MODEL_ID,
        model_kwargs={
            "max_tokens": 4096,
            "temperature": 0.7,
        }
    )


# =============================================================================
# Multi-Tenant Utilities
# =============================================================================

def extract_tenant_id() -> str:
    """Extract tenant ID from request headers.

    Returns:
        Tenant ID string

    Raises:
        ValueError: If tenant_id is not found
    """
    tenant_id = request.headers.get(TENANT_ID_HEADER)

    if not tenant_id:
        raise ValueError("Missing tenant_id in request headers")

    return tenant_id


def with_tenant_context(func):
    """Decorator to add tenant context to request handling."""
    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            tenant_id = extract_tenant_id()
            request_id = request.headers.get("x-request-id", datetime.utcnow().isoformat())

            # Bind logging context
            log = logger.bind(
                tenant_id=tenant_id,
                request_id=request_id,
                endpoint=request.path
            )

            return func(tenant_id=tenant_id, request_id=request_id, log=log, *args, **kwargs)

        except ValueError as e:
            return jsonify({"error": str(e)}), 403

    return wrapper


