def create_researcher_agent(llm: ChatBedrock) -> Agent:
    """Create the Researcher agent.

    The Researcher is responsible for gathering and analyzing information.

    Args:
        llm: Language model instance

    Returns:
        Configured Agent
    """
    return Agent(
        role="Senior Researcher",
        goal="Gather comprehensive, accurate information to support decision-making",
        backstory="""You are an expert researcher with years of experience in
        analyzing complex topics. You excel at finding relevant information,
        identifying patterns, and synthesizing insights from multiple sources.
        You always cite your sources and distinguish between facts and opinions.""",
        llm=llm,
        tools=[search_knowledge_base, analyze_data],
        verbose=True,
        allow_delegation=False
    )


def create_analyst_agent(llm: ChatBedrock) -> Agent:
    """Create the Analyst agent.

    The Analyst processes research findings and draws conclusions.

    Args:
        llm: Language model instance

    Returns:
        Configured Agent
    """
    return Agent(
        role="Senior Analyst",
        goal="Transform research into actionable insights and recommendations",
        backstory="""You are a seasoned analyst who excels at critical thinking
        and strategic analysis. You take complex information and distill it into
        clear, actionable recommendations. You consider multiple perspectives
        and potential outcomes in your analysis.""",
        llm=llm,
        tools=[analyze_data],
        verbose=True,
        allow_delegation=False
    )


def create_writer_agent(llm: ChatBedrock) -> Agent:
    """Create the Writer agent.

    The Writer produces the final deliverable.

    Args:
        llm: Language model instance

    Returns:
        Configured Agent
    """
    return Agent(
        role="Senior Writer",
        goal="Create clear, compelling, and well-structured content",
        backstory="""You are an accomplished writer who transforms complex
        analysis into engaging, easy-to-understand content. You have a talent
        for structuring information logically and writing in a way that
        resonates with your audience.""",
        llm=llm,
        tools=[generate_report],
        verbose=True,
        allow_delegation=False
    )


# =============================================================================
# Task Definitions
# =============================================================================

def create_research_task(topic: str, researcher: Agent) -> Task:
    """Create the research task.

    Args:
        topic: Topic to research
        researcher: Researcher agent

    Returns:
        Configured Task
    """
    return Task(
        description=f"""Research the following topic thoroughly:

Topic: {topic}

Your research should:
1. Identify key facts and data points
2. Find relevant examples and case studies
3. Note any conflicting information or debates
4. Highlight important trends or patterns

Provide a comprehensive research summary.""",
        expected_output="A detailed research summary with key findings, data points, and sources",
        agent=researcher
    )


def create_analysis_task(analyst: Agent, context_tasks: List[Task]) -> Task:
    """Create the analysis task.

    Args:
        analyst: Analyst agent
        context_tasks: Tasks providing context (research task)

    Returns:
        Configured Task
    """
    return Task(
        description="""Analyze the research findings and develop insights:

Based on the research provided:
1. Identify the most important findings
2. Draw conclusions from the data
3. Identify potential risks and opportunities
4. Develop actionable recommendations

Provide a thorough analysis with clear recommendations.""",
        expected_output="A strategic analysis with key insights, conclusions, and actionable recommendations",
        agent=analyst,
        context=context_tasks
    )


def create_writing_task(writer: Agent, context_tasks: List[Task]) -> Task:
    """Create the writing task.

    Args:
        writer: Writer agent
        context_tasks: Tasks providing context (research and analysis tasks)

    Returns:
        Configured Task
    """
    return Task(
        description="""Create a comprehensive final report:

Using the research and analysis provided:
1. Structure the content logically
2. Write clear, engaging prose
3. Include an executive summary
4. Add conclusions and next steps

The report should be professional and actionable.""",
        expected_output="A well-structured, professional report with executive summary, findings, analysis, and recommendations",
        agent=writer,
        context=context_tasks
    )


# =============================================================================
# Crew Assembly
# =============================================================================

def create_crew(topic: str, tenant_id: str) -> Crew:
    """Assemble the multi-agent crew for the task.

    Args:
        topic: The topic/task to work on
        tenant_id: Tenant identifier

    Returns:
        Configured Crew
    """
    # Create LLM with tenant context
    llm = create_bedrock_llm(tenant_id)

    # Create agents
    researcher = create_researcher_agent(llm)
    analyst = create_analyst_agent(llm)
    writer = create_writer_agent(llm)

    # Create tasks
    research_task = create_research_task(topic, researcher)
    analysis_task = create_analysis_task(analyst, [research_task])
    writing_task = create_writing_task(writer, [research_task, analysis_task])

    # Assemble crew
    crew = Crew(
        agents=[researcher, analyst, writer],
        tasks=[research_task, analysis_task, writing_task],
        process=Process.sequential,  # Tasks execute in order
        verbose=True
    )

    return crew


