@app.route("/execute", methods=["POST"])
@with_tenant_context
def execute_crew(tenant_id: str, request_id: str, log):
    """Execute the multi-agent crew on a task.

    Expected request body:
    {
        "task": "The task/topic for the crew to work on"
    }
    """
    log.info("crew_execution_started")

    try:
        # Parse request
        body = request.get_json()
        task_input = body.get("task")

        if not task_input:
            return jsonify({"error": "Missing 'task' in request body"}), 400

        # Create and execute crew
        crew = create_crew(task_input, tenant_id)

        log.info("crew_kickoff", task=task_input[:100])
        result = crew.kickoff()

        log.info("crew_execution_completed", result_length=len(str(result)))

        return jsonify({
            "result": str(result),
            "request_id": request_id,
            "agents_used": ["researcher", "analyst", "writer"],
            "process": "sequential"
        })

    except Exception as e:
        log.error("crew_execution_failed", error=str(e))
        return jsonify({
            "error": str(e),
            "request_id": request_id
        }), 500


